Trigger_TemplateProps.Template_Code:
	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot update %Parent because %Child exists.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot delete %Parent because %Child exists.');
	END

	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot insert %Child because %Parent does not exist.');
	END

	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot update %Child because %Parent does not exist.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot delete %Child because %Parent exists.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot insert %Parent because %Child does not.');
	END

%Decl(i,1)
%ForEachParentRel() {
%If(%RelTemplate)
{CREATE TRIGGER %ProcedureOwner(.)%TriggerName%If(%<>(%:i,1)){%:i}
  %Fire %Action
  ON %TableOwner(.)%TableName
  %RefClause
  %Scope
  %TriggerWhen
  %RelTemplate
  %DBMSTriggerDelim
  %=(i,%+(%:i,1))
}}

%ForEachChildRel() {
%If(%RelTemplate)
{CREATE TRIGGER %ProcedureOwner(.)%TriggerName%If(%<>(%:i,1)){%:i}
  %Fire %Action
  ON %TableOwner(.)%TableName
  %RefClause
  %Scope
  %TriggerWhen
  %RelTemplate
  %DBMSTriggerDelim
  %=(i,%+(%:i,1))
}}

	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot update %Parent because %Child exists.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot delete %Parent because %Child exists.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot delete %Child because %Parent exists.');
	END

	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot update %Child because %Parent does not exist.');
	END

	BEGIN ATOMIC
       SIGNAL SQLSTATE '75001' ('Cannot insert %Child because %Parent does not exist.');
	END

	BEGIN ATOMIC
     SIGNAL SQLSTATE '75001' ('Cannot insert %Parent because %Child does not.');
	END
